input double InpMinTP_Points    = 500;  // TP mГӯnimo en puntos (XAUUSD: 500 = $5.00 mov)
input double InpMaxTP_Points    = 3000; // TP mГЎximo en puntos (XAUUSD: 3000 = $30.00 mov)

input group "в•җв•җв•җв•җв•җв•җ BREAKEVEN ADAPTATIVO в•җв•җв•җв•җв•җв•җ"
input bool   InpBE_Enabled      = true;  // Activar BE automГЎtico       [Tier2: true/false]
input double InpBE_TriggerPct   = 50.0; // % del TP para activar BE    [Tier2: 30,50,70]
input double InpBE_LockPoints   = 10;   // Puntos de colchГіn sobre entrada al activar BE

input group "в•җв•җв•җв•җв•җв•җ SPS REDISEГ‘ADO в•җв•җв•җв•җв•җв•җ"
input bool   InpSPS_Enabled     = true;  // Activar filtro SPS
input int    InpSPS_Lookback    = 8;     // Velas pre-rango analizadas  [Tier2: 4вҖ“16 step 4]
input double InpSPS_Threshold   = 0.35; // Umbral seГұal [0вҖ“1]          [Tier2: 0.20вҖ“0.50 step 0.10]
input bool   InpSPS_RecencyBias = true;  // Ponderar velas mГЎs recientes
input bool   InpSPS_Debug       = false; // Imprimir score SPS en log

input group "в•җв•җв•җв•җв•җв•җ RIESGO в•җв•җв•җв•җв•җв•җ"
input bool   InpUsePercentRisk  = false; // true=%balance | false=USD fijo
input double InpRiskUSD         = 0.5;  // Riesgo USD fijo por trade
input double InpRiskPercent     = 1.0;  // % balance (si InpUsePercentRisk=true)

input group "в•җв•җв•җв•җв•җв•җ CONTROL DE TRADES в•җв•җв•җв•җв•җв•җ"
input bool   InpOnlyOnePerDay   = true;  // Solo un trade ejecutado por dГӯa
input ulong  InpMagicNumber     = 20260404;
input string InpComment         = "ORB_v3";

//+------------------------------------------------------------------+
//  ENUMERADORES Y GLOBALES
//+------------------------------------------------------------------+

enum SPS_Signal { SPS_BULLISH, SPS_BEARISH, SPS_NEUTRAL };

CTrade   g_trade;
int      g_atrHandle    = INVALID_HANDLE;
datetime g_lastBarTime  = 0;
datetime g_currentDay   = 0;   // dГӯa de trading actual (para resetear flags)
datetime g_tradeDay     = 0;   // dГӯa en que se ejecutГі el Гәltimo trade
bool     g_ordersPlaced = false;

//+------------------------------------------------------------------+
//| OnInit                                                            |
//+------------------------------------------------------------------+
int OnInit()
{
    //--- Validar timeframe
    if(_Period != PERIOD_M5)
    {
        Alert("ORB_v3 requiere timeframe M5. GrГЎfico actual: ", EnumToString(_Period));
        return INIT_FAILED;
    }

    //--- Crear handle ATR
    g_atrHandle = iATR(_Symbol, PERIOD_M5, InpATR_Period);
    if(g_atrHandle == INVALID_HANDLE)
    {
        Print("[ORB_v3] ERROR: no se pudo inicializar ATR(", InpATR_Period, ")");
        return INIT_FAILED;
    }

    //--- Configurar objeto trade
    g_trade.SetExpertMagicNumber(InpMagicNumber);
    g_trade.SetDeviationInPoints(30);
    g_trade.SetTypeFilling(ORDER_FILLING_IOC);
    g_trade.SetAsyncMode(false);

