        InpSessionHour, InpSessionMinute, InpRangeCandles);
    PrintFormat("в•‘ ATR(%2d)  : TPГ—%.1f  SLГ—%.1f  Min=%4.0fpts Max=%5.0fpts в•‘",
        InpATR_Period, InpTP_ATR_Mult, InpSL_ATR_Mult, InpMinTP_Points, InpMaxTP_Points);
    PrintFormat("в•‘ BE       : %s  Trigger=%.0f%%  Lock=%dptos              в•‘",
