//+------------------------------------------------------------------+
//| OnDeinit                                                          |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
    if(g_atrHandle != INVALID_HANDLE)
        IndicatorRelease(g_atrHandle);
    Print("[ORB_v3] EA desactivado. RazГіn: ", reason);
}

//+------------------------------------------------------------------+
//| OnTick вҖ” flujo principal                                          |
//+------------------------------------------------------------------+
void OnTick()
{
    //--- 1. Gestionar BE en posiciones abiertas (cada tick)
    ManageBreakeven();

    //--- 2. Cancelar pendientes si ya hay posiciГіn (cada tick)
    CheckCancelOpposingPending();

    //--- 3. Detectar nueva barra
    datetime curBarTime = iTime(_Symbol, PERIOD_M5, 0);
    if(curBarTime == g_lastBarTime) return;
    g_lastBarTime = curBarTime;

    //--- 4. Calcular "hoy" (dГӯa sin hora)
    MqlDateTime dt;
    TimeToStruct(curBarTime, dt);
    datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               dt.year, dt.mon, dt.day));

    //--- 5. Nuevo dГӯa вҶ’ resetear estado y limpiar pendientes stale
    if(today != g_currentDay)
    {
        g_currentDay   = today;
        g_ordersPlaced = false;
        CancelAllPending();
    }

    //--- 6. Guards de sesiГіn
    if(g_ordersPlaced) return;                                 // ya se colocaron hoy
    if(InpOnlyOnePerDay && today == g_tradeDay) return;        // ya se ejecutГі un trade hoy

    //--- 7. Verificar hora de sesiГіn (solo en la barra exacta)
    if(dt.hour != InpSessionHour || dt.min != InpSessionMinute) return;

    //--- 8. Calcular y colocar Гіrdenes ORB
    PlaceORBOrders(today);
}

//+------------------------------------------------------------------+
//| PlaceORBOrders вҖ” construye rango, SPS y coloca Гіrdenes           |
//+------------------------------------------------------------------+
void PlaceORBOrders(datetime today)
{
    //--- Barras necesarias: rango + SPS + margen
    int barsNeeded = InpRangeCandles + InpSPS_Lookback + 2;

    //--- Copiar OHLC desde barra 1 (mГЎs reciente cerrada) hacia atrГЎs
    double hi[], lo[], op[], cl[];
    ArraySetAsSeries(hi, true);  ArraySetAsSeries(lo, true);
    ArraySetAsSeries(op, true);  ArraySetAsSeries(cl, true);

    if(CopyHigh (_Symbol, PERIOD_M5, 1, barsNeeded, hi) != barsNeeded)
        { Print("[ORB_v3] CopyHigh error: barras insuficientes");  return; }
    if(CopyLow  (_Symbol, PERIOD_M5, 1, barsNeeded, lo) != barsNeeded)
        { Print("[ORB_v3] CopyLow error: barras insuficientes");   return; }
    if(CopyOpen (_Symbol, PERIOD_M5, 1, barsNeeded, op) != barsNeeded)
        { Print("[ORB_v3] CopyOpen error: barras insuficientes");  return; }
    if(CopyClose(_Symbol, PERIOD_M5, 1, barsNeeded, cl) != barsNeeded)
        { Print("[ORB_v3] CopyClose error: barras insuficientes"); return; }

    //--- ATR de la barra mГЎs reciente cerrada
    double atrArr[];
    ArraySetAsSeries(atrArr, true);
    if(CopyBuffer(g_atrHandle, 0, 1, 1, atrArr) != 1)
        { Print("[ORB_v3] ATR buffer error"); return; }
    double atr = atrArr[0];
    if(atr <= _Point)
        { PrintFormat("[ORB_v3] ATR=%.5f demasiado pequeГұo, skip", atr); return; }

    //--- в•җв•җв•җ RANGO ORB в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // ГҚndices 0..InpRangeCandles-1 (0 = barra 1 del grГЎfico = Гәltima cerrada)
    double rangeHigh = hi[0];
    double rangeLow  = lo[0];
    for(int i = 1; i < InpRangeCandles; i++)
    {
        if(hi[i] > rangeHigh) rangeHigh = hi[i];
        if(lo[i] < rangeLow)  rangeLow  = lo[i];
    }
    double rangeSize = rangeHigh - rangeLow;

    //--- в•җв•җв•җ SPS REDISEГ‘ADO в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // Velas pre-rango: Гӯndices InpRangeCandles .. InpRangeCandles+InpSPS_Lookback-1
    // La vela en Гӯndice InpRangeCandles es inmediatamente anterior al rango
    SPS_Signal sps = SPS_NEUTRAL;
    if(InpSPS_Enabled)
        sps = CalcSPS(op, cl, hi, lo, InpRangeCandles, InpSPS_Lookback);

    //--- в•җв•җв•җ DISTANCIAS ATR в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    double minTP  = InpMinTP_Points * _Point;          // piso TP en precio
    double maxTP  = InpMaxTP_Points * _Point;          // techo TP en precio
    double tpDist = MathMax(minTP, MathMin(maxTP, atr * InpTP_ATR_Mult));
    double minSL  = minTP * 0.25;                      // SL floor = 25% del TP mГӯnimo
    double slDist = MathMax(minSL, atr * InpSL_ATR_Mult);

    //--- в•җв•җв•җ TAMAГ‘O DE POSICIГ“N в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    double lots = CalcLots(slDist);
    if(lots <= 0.0)
    {
        PrintFormat("[ORB_v3] Lote invГЎlido. SL=%.5f ATR=%.5f SL_mult=%.1f",
                    slDist, atr, InpSL_ATR_Mult);
        return;
    }

    //--- в•җв•җв•җ PRECIOS ACTUALES в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    double ask    = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
    double bid    = SymbolInfoDouble(_Symbol, SYMBOL_BID);
    double spread = ask - bid;

    //--- в•җв•җв•җ NIVELES DE ENTRADA в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    // BUY STOP: encima del mГЎximo del rango + spread
    double buyEntry  = NormalizeDouble(rangeHigh + spread, _Digits);
    double buySL     = NormalizeDouble(buyEntry  - slDist, _Digits);
    double buyTP     = NormalizeDouble(buyEntry  + tpDist, _Digits);

    // SELL STOP: debajo del mГӯnimo del rango + spread
    double sellEntry = NormalizeDouble(rangeLow  - spread, _Digits);
    double sellSL    = NormalizeDouble(sellEntry + slDist, _Digits);
    double sellTP    = NormalizeDouble(sellEntry - tpDist, _Digits);

    // ExpiraciГіn: fin del dГӯa actual (23:59:59)
    datetime expiry = today + 86399;

    bool placed = false;

    //--- в•җв•җв•җ LOG RANGO в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    PrintFormat("[ORB_v3] %s | Rango [%.2f вҖ“ %.2f] %.0fpts | ATR=%.2f | TP=%.0fpts SL=%.0fpts | lots=%.2f | SPS=%s",
        TimeToString(TimeCurrent(), TIME_DATE|TIME_MINUTES),
        rangeLow, rangeHigh, rangeSize / _Point,
        atr, tpDist / _Point, slDist / _Point, lots, SPSName(sps));

    //--- в•җв•җв•җ BUY STOP (omitir si SPS = BEARISH) в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if(sps != SPS_BEARISH)
    {
        if(buyEntry > ask)  // vГЎlido: orden stop sobre mercado
        {
            if(g_trade.BuyStop(lots, buyEntry, _Symbol, buySL, buyTP,
                               ORDER_TIME_SPECIFIED, expiry, InpComment))
            {
                placed = true;
                PrintFormat("[ORB_v3] вң“ BUY STOP   | Entry=%.2f SL=%.2f TP=%.2f | SPS=%s",
                    buyEntry, buySL, buyTP, SPSName(sps));
            }
            else
                PrintFormat("[ORB_v3] вң— BUY STOP error [%d]: %s",
                    g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
        }
        else
            PrintFormat("[ORB_v3] BUY STOP skipped: entry(%.2f) <= ask(%.2f) вҖ” breakout ya ocurriГі",
                buyEntry, ask);
    }

    //--- в•җв•җв•җ SELL STOP (omitir si SPS = BULLISH) в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if(sps != SPS_BULLISH)
    {
        if(sellEntry < bid)  // vГЎlido: orden stop bajo mercado
        {
            if(g_trade.SellStop(lots, sellEntry, _Symbol, sellSL, sellTP,
                                ORDER_TIME_SPECIFIED, expiry, InpComment))
            {
                placed = true;
                PrintFormat("[ORB_v3] вң“ SELL STOP  | Entry=%.2f SL=%.2f TP=%.2f | SPS=%s",
                    sellEntry, sellSL, sellTP, SPSName(sps));
            }
            else
                PrintFormat("[ORB_v3] вң— SELL STOP error [%d]: %s",
                    g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
        }
        else
            PrintFormat("[ORB_v3] SELL STOP skipped: entry(%.2f) >= bid(%.2f) вҖ” breakout ya ocurriГі",
                sellEntry, bid);
    }

    if(placed)
        g_ordersPlaced = true;

    if(!placed)
        Print("[ORB_v3] Ninguna orden colocada en esta sesiГіn");
}

//+------------------------------------------------------------------+
//| CalcSPS вҖ” Session Pressure Score RediseГұado                      |
//|                                                                  |
//| Analiza las velas inmediatamente anteriores al rango ORB.        |
//| Lookback corto (4вҖ“16) = captura momentum de 20вҖ“80 min            |
//| Recency bias: vela mГЎs cercana al rango tiene mayor peso         |
//|                                                                  |
//| score вҲҲ [-1, +1]                                                 |
//|  вүҘ +threshold вҶ’ BULLISH (solo BUY)                              |
//|  вүӨ -threshold вҶ’ BEARISH (solo SELL)                             |
//|  entre Вұthr   вҶ’ NEUTRAL (ambas Гіrdenes)                         |
//+------------------------------------------------------------------+
SPS_Signal CalcSPS(const double &op[], const double &cl[],
                   const double &hi[], const double &lo[],
                   int startIdx, int lookback)
{
    double totalWeight   = 0.0;
    double weightedScore = 0.0;
    int    validCandles  = 0;

    for(int i = 0; i < lookback; i++)
    {
        int j = startIdx + i;  // j=startIdx вҶ’ vela justo antes del rango (mГЎs reciente)

        double barRange = hi[j] - lo[j];
        if(barRange <= 0.0) continue;

        // body_ratio: calidad de la vela [0, 1]
        double bodyRatio = MathAbs(cl[j] - op[j]) / barRange;

        // direction: +1 alcista, -1 bajista
        int direction = (cl[j] >= op[j]) ? 1 : -1;

        // Recency weight: i=0 (mГЎs cercana al rango) вҶ’ peso mГЎximo
        // i=lookback-1 (mГЎs antigua) вҶ’ peso mГӯnimo pero > 0
        double weight = InpSPS_RecencyBias
                        ? (double)(lookback - i) / (double)lookback
                        : 1.0;

        weightedScore += (double)direction * bodyRatio * weight;
        totalWeight   += weight;
        validCandles++;
    }

    if(validCandles == 0 || totalWeight <= 0.0)
    {
        if(InpSPS_Debug) Print("[SPS] Sin velas vГЎlidas вҶ’ NEUTRAL");
        return SPS_NEUTRAL;
    }

    double score = weightedScore / totalWeight;  // normalizado [-1, +1]

    if(InpSPS_Debug)
        PrintFormat("[SPS] score=%.4f  threshold=Вұ%.2f  lookback=%d  вҶ’ %s",
            score, InpSPS_Threshold, lookback,
            score >=  InpSPS_Threshold ? "BULLISH вҶ‘" :
            score <= -InpSPS_Threshold ? "BEARISH вҶ“" : "NEUTRAL вҶ”");

    if(score >=  InpSPS_Threshold) return SPS_BULLISH;
    if(score <= -InpSPS_Threshold) return SPS_BEARISH;
    return SPS_NEUTRAL;
}

//+------------------------------------------------------------------+
//| ManageBreakeven вҖ” BE adaptativo basado en % del TP               |
//|                                                                  |
//| Se activa cuando el precio supera:                               |
//|   BUY:  entry + (TP_dist Г— InpBE_TriggerPct / 100)             |
//|   SELL: entry - (TP_dist Г— InpBE_TriggerPct / 100)             |
//|                                                                  |
//| Mueve SL a: entry + InpBE_LockPoints (BUY)                      |
//|           : entry - InpBE_LockPoints (SELL)                     |
//+------------------------------------------------------------------+
void ManageBreakeven()
{
    if(!InpBE_Enabled) return;

    for(int i = PositionsTotal() - 1; i >= 0; i--)
    {
        ulong ticket = PositionGetTicket(i);
        if(!PositionSelectByTicket(ticket)) continue;
        if((ulong)PositionGetInteger(POSITION_MAGIC) != InpMagicNumber) continue;
        if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

        ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
        double entry  = PositionGetDouble(POSITION_PRICE_OPEN);
        double sl     = PositionGetDouble(POSITION_SL);
        double tp     = PositionGetDouble(POSITION_TP);

        if(tp <= 0) continue;  // sin TP configurado, saltar

        double curPrice = (posType == POSITION_TYPE_BUY)
                          ? SymbolInfoDouble(_Symbol, SYMBOL_BID)
                          : SymbolInfoDouble(_Symbol, SYMBOL_ASK);

        double tpDist      = MathAbs(tp - entry);
        double triggerDist = tpDist * InpBE_TriggerPct / 100.0;
        double lockDist    = InpBE_LockPoints * _Point;
        double newSL;

        if(posType == POSITION_TYPE_BUY)
        {
            double triggerLevel = entry + triggerDist;
            if(curPrice < triggerLevel) continue;               // no alcanzГі trigger
            newSL = NormalizeDouble(entry + lockDist, _Digits);
            if(sl >= newSL - _Point) continue;                  // ya estГЎ en BE o mejor
        }
        else  // SELL
        {
            double triggerLevel = entry - triggerDist;
            if(curPrice > triggerLevel) continue;
            newSL = NormalizeDouble(entry - lockDist, _Digits);
            if(sl <= newSL + _Point) continue;                  // ya estГЎ en BE o mejor
        }

        if(g_trade.PositionModify(ticket, newSL, tp))
            PrintFormat("[ORB_v3 BE] ticket=%llu | SL вҶ’ %.2f (entryВұ%dpts) | triggered at %.2f",
                ticket, newSL, (int)InpBE_LockPoints, curPrice);
        else
            PrintFormat("[ORB_v3 BE] PositionModify error [%d]: %s",
                g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
    }
}

//+------------------------------------------------------------------+
//| CheckCancelOpposingPending вҖ” si hay posiciГіn abierta, cancela   |
//| todas las Гіrdenes pendientes del EA                              |
//+------------------------------------------------------------------+
void CheckCancelOpposingPending()
{
    for(int i = 0; i < PositionsTotal(); i++)
    {
        ulong ticket = PositionGetTicket(i);
        if(!PositionSelectByTicket(ticket)) continue;
        if((ulong)PositionGetInteger(POSITION_MAGIC) != InpMagicNumber) continue;
        if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

        // Registrar el dГӯa del trade ejecutado
        datetime posTime = (datetime)PositionGetInteger(POSITION_TIME);
        MqlDateTime dtPos;
        TimeToStruct(posTime, dtPos);
        datetime posDay = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                                    dtPos.year, dtPos.mon, dtPos.day));
        if(posDay > g_tradeDay) g_tradeDay = posDay;

        // Cancelar pendientes contrarias
        CancelAllPending();
        return;  // solo necesitamos confirmar que hay una posiciГіn
    }
}

//+------------------------------------------------------------------+
//| CancelAllPending вҖ” cancela todos los pendientes del EA           |
//+------------------------------------------------------------------+
void CancelAllPending()
{
    for(int i = OrdersTotal() - 1; i >= 0; i--)
    {
        ulong ticket = OrderGetTicket(i);
        if(!OrderSelect(ticket)) continue;
        if((ulong)OrderGetInteger(ORDER_MAGIC) != InpMagicNumber) continue;
        if(OrderGetString(ORDER_SYMBOL) != _Symbol) continue;

        if(!g_trade.OrderDelete(ticket))
            PrintFormat("[ORB_v3] OrderDelete error [%d]: %s ticket=%llu",
                g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription(), ticket);
    }
}

//+------------------------------------------------------------------+
//| CalcLots вҖ” tamaГұo de posiciГіn basado en riesgo y SL dinГЎmico    |
//|                                                                  |
//| FГіrmula: lots = risk_amount / (slDist/tickSize Г— tickValue)      |
//| Funciona para cualquier sГӯmbolo (XAUUSD, Гӯndices, forex)        |
//+------------------------------------------------------------------+
double CalcLots(double slDist)
{
    double riskAmount = InpUsePercentRisk
                      ? AccountInfoDouble(ACCOUNT_BALANCE) * InpRiskPercent / 100.0
                      : InpRiskUSD;
    if(riskAmount <= 0) return 0;

    double tickSz  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
    double tickVal = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
    if(tickSz <= 0 || tickVal <= 0 || slDist <= 0) return 0;

    double riskPerLot = (slDist / tickSz) * tickVal;  // riesgo en $ por 1 lot con este SL
    if(riskPerLot <= 0) return 0;

    double raw     = riskAmount / riskPerLot;
    double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
    double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
    double lotMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

    double lots = MathFloor(raw / lotStep) * lotStep;
    lots = MathMax(lotMin, MathMin(lotMax, lots));
    return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| OnTradeTransaction вҖ” cancelaciГіn inmediata al ejecutarse orden   |
//| Complemento de CheckCancelOpposingPending (que actГәa en OnTick) |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
{
    // Solo nos interesan deals de entrada (DEAL_ENTRY_IN)
    if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;

    if(!HistoryDealSelect(trans.deal)) return;
    if((ulong)HistoryDealGetInteger(trans.deal, DEAL_MAGIC)  != InpMagicNumber) return;
    if(HistoryDealGetString(trans.deal, DEAL_SYMBOL)         != _Symbol) return;
    if((ENUM_DEAL_ENTRY)HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_IN) return;

    // PosiciГіn abierta вҶ’ cancelar pendientes inmediatamente
    datetime dealTime = (datetime)HistoryDealGetInteger(trans.deal, DEAL_TIME);
    MqlDateTime dtDeal;
    TimeToStruct(dealTime, dtDeal);
    g_tradeDay = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                           dtDeal.year, dtDeal.mon, dtDeal.day));
    CancelAllPending();
    PrintFormat("[ORB_v3 TX] Deal %llu ejecutado вҶ’ pendientes cancelados", trans.deal);
}

//+------------------------------------------------------------------+
//| SPSName вҖ” nombre legible de la seГұal SPS                        |
//+------------------------------------------------------------------+
string SPSName(SPS_Signal s)
{
    switch(s)
    {
        case SPS_BULLISH: return "BULLISH вҶ‘";
        case SPS_BEARISH: return "BEARISH вҶ“";
        default:          return "NEUTRAL вҶ”";
    }
}

