//+------------------------------------------------------------------+
//| ManageBreakeven вҖ” BE basado en ATR (v3.1)                        |
//|                                                                  |
//| El trigger NO depende del TP вҖ” usa el mismo ATR del SL.          |
//| Se activa cuando el precio supera:                               |
//|   BUY:  entry + (ATR_at_entry Г— InpBE_ATR_Mult)                 |
//|   SELL: entry - (ATR_at_entry Г— InpBE_ATR_Mult)                 |
//|                                                                  |
//| El ATR_at_entry se reconstruye desde el SL actual:               |
//|   slDist = MathAbs(entry - sl)                                   |
//|   atr_implied = slDist / InpSL_ATR_Mult                          |
//|   triggerDist = atr_implied Г— InpBE_ATR_Mult                     |
//|                                                                  |
//| Mueve SL a: entry + InpBE_LockPoints (BUY)                       |
//|           : entry - InpBE_LockPoints (SELL)                      |
//+------------------------------------------------------------------+
void ManageBreakeven()
{
    if(!InpBE_Enabled) return;

    // Guardia logica: BE_mult debe ser menor que SL_mult
    if(InpBE_ATR_Mult >= InpSL_ATR_Mult)
    {
        static bool warningLogged = false;
        if(!warningLogged)
        {
            PrintFormat("[ORB_v3 BE] ADVERTENCIA: InpBE_ATR_Mult(%.1f) >= InpSL_ATR_Mult(%.1f) вҖ” BE desactivado logicamente",
                InpBE_ATR_Mult, InpSL_ATR_Mult);
            warningLogged = true;
        }
        return;
    }

    for(int i = PositionsTotal() - 1; i >= 0; i--)
    {
        ulong ticket = PositionGetTicket(i);
        if(!PositionSelectByTicket(ticket)) continue;
        if((ulong)PositionGetInteger(POSITION_MAGIC) != InpMagicNumber) continue;
        if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;

        ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
        double entry = PositionGetDouble(POSITION_PRICE_OPEN);
        double sl    = PositionGetDouble(POSITION_SL);
        double tp    = PositionGetDouble(POSITION_TP);

        if(tp <= 0 || sl <= 0) continue;

        double curPrice = (posType == POSITION_TYPE_BUY)
                          ? SymbolInfoDouble(_Symbol, SYMBOL_BID)
                          : SymbolInfoDouble(_Symbol, SYMBOL_ASK);

        // Reconstruir ATR implГӯcito desde el SL colocado en la entrada
        // slDist = ATR Г— InpSL_ATR_Mult  вҶ’  atr_implied = slDist / InpSL_ATR_Mult
        double slDist       = MathAbs(entry - sl);
        double atrImplied   = (InpSL_ATR_Mult > 0) ? slDist / InpSL_ATR_Mult : slDist;
        double triggerDist  = atrImplied * InpBE_ATR_Mult;
        double lockDist     = InpBE_LockPoints * _Point;
        double newSL;

        if(posType == POSITION_TYPE_BUY)
        {
            double triggerLevel = entry + triggerDist;
            if(curPrice < triggerLevel) continue;              // no alcanzo trigger
            newSL = NormalizeDouble(entry + lockDist, _Digits);
            if(sl >= newSL - _Point) continue;                 // ya esta en BE o mejor
        }
        else  // SELL
        {
            double triggerLevel = entry - triggerDist;
            if(curPrice > triggerLevel) continue;
            newSL = NormalizeDouble(entry - lockDist, _Digits);
            if(sl <= newSL + _Point) continue;                 // ya esta en BE o mejor
        }

        if(g_trade.PositionModify(ticket, newSL, tp))
            PrintFormat("[ORB_v3 BE] ticket=%llu | SL -> %.2f (entry+-%.0fpts) | ATR_impl=%.2f | trigger=%.2f | cur=%.2f",
                ticket, newSL, InpBE_LockPoints, atrImplied, entry + (posType==POSITION_TYPE_BUY?1:-1)*triggerDist, curPrice);
        else
            PrintFormat("[ORB_v3 BE] PositionModify error [%d]: %s",
                g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
    }
}

