{"language": "plaintext", "code": "
input group "══════ SESIÓN Y RANGO ══════"
input int    InpSessionHour     = 17;    // Hora sesión (server time)   [Tier3: 14,15,17]
input int    InpSessionMinute   = 0;     // Minuto sesión
input int    InpRangeCandles    = 4;     // Velas M5 del rango ORB      [Tier1: 2–8 step 2]

input group "══════ ATR DINÁMICO ══════"
input int    InpATR_Period      = 14;    // Período ATR                 [Tier3: 7,14,21]
input double InpTP_ATR_Mult     = 1.5;  // Multiplicador ATR → TP      [Tier1: 1.0–3.0 step 0.5]
input double InpSL_ATR_Mult     = 1.0;  // Multiplicador ATR → SL      [Tier1: 0.5–2.0 step 0.5]
input double InpMinTP_Points    = 500;  // TP mínimo en puntos (XAUUSD: 500 = $5.00 mov)
input double InpMaxTP_Points    = 3000; // TP máximo en puntos (XAUUSD: 3000 = $30.00 mov)

input group "══════ BREAKEVEN ATR-BASED ══════"
input bool   InpBE_Enabled      = true;  // Activar BE automático          [Tier2: true/false]
input double InpBE_ATR_Mult     = 0.5;  // ATR × mult → trigger BE        [Tier2: 0.3-0.9 step 0.2]
// RESTRICCION LOGICA: InpBE_ATR_Mult < InpSL_ATR_Mult siempre
// Ejemplo SL x1.0 BE x0.5: BE activa cuando precio recorrio 50% del SL a favor
input double InpBE_LockPoints   = 10;   // Puntos de colchon sobre entrada al activar BE

input group "══════ SPS REDISEÑADO ══════"
input bool   InpSPS_Enabled     = true;  // Activar filtro SPS
input int    InpSPS_Lookback    = 8;     // Velas pre-rango analizadas  [Tier2: 4–16 step 4]
input double InpSPS_Threshold   = 0.35; // Umbral señal [0–1]          [Tier2: 0.20–0.50 step 0.10]
input bool   InpSPS_RecencyBias = true;  // Ponderar velas más recientes
input bool   InpSPS_Debug       = false; // Imprimir score SPS en log

input group "══════ RIESGO ══════"
input bool   InpUsePercentRisk  = false; // true=%balance | false=USD fijo
input double InpRiskUSD         = 0.5;  // Riesgo USD fijo por trade
input double InpRiskPercent     = 1.0;  // % balance (si InpUsePercentRisk=true)

input group "══════ CONTROL DE TRADES ══════"
input bool   InpOnlyOnePerDay   = true;  // Solo un trade ejecutado por día
input ulong  InpMagicNumber     = 20260404;
input string InpComment         = "ORB_v3";

//+------------------------------------------------------------------+
//  ENUMERADORES Y GLOBALES
//+------------------------------------------------------------------+

enum SPS_Signal { SPS_BULLISH, SPS_BEARISH, SPS_NEUTRAL };

CTrade   g_trade;
int      g_atrHandle    = INVALID_HANDLE;
datetime g_lastBarTime  = 0;
datetime g_currentDay   = 0;   // día de trading actual (para resetear flags)
datetime g_tradeDay     = 0;   // día en que se ejecutó el último trade
bool     g_ordersPlaced = false;

