input bool   InpBE_Enabled      = true;  // Activar BE                [Tier2 paso-A: probar false]
input double InpBE_ATR_Mult     = 0.5;  // ATR mult вҶ’ trigger BE     [Tier2: 0.3 step0.2 0.7  вҶ’ valores: 0.3,0.5,0.7]
// RESTRICCION: InpBE_ATR_Mult < InpSL_ATR_Mult  (BE actua antes que el SL)
// Con SL x1.0 y BE x0.5: trigger a los $5 de movimiento favorable en dia tipico
input double InpBE_LockPoints   = 10;   // Colchon en puntos sobre entry al activar BE (no optimizar)

input group "====== SPS REDISENIADO ======"
input bool   InpSPS_Enabled     = true;  // Activar SPS               [Tier2 paso-B: probar false]
input int    InpSPS_Lookback    = 4;    // Velas pre-rango            [Tier2: 4 step4 8  вҶ’ valores: 4,8]
// NOTA: Lookback=4 (20 min antes del rango) confirma datos IS.
//       Lookback corto captura momentum inmediato al breakout.
input double InpSPS_Threshold   = 0.30; // Umbral senal [0-1]        [Tier2: 0.20 step0.10 0.40  вҶ’ valores: 0.20,0.30,0.40]
input bool   InpSPS_RecencyBias = true;  // Ponderar velas mas recientes (no optimizar вҖ” true gana en IS)
input bool   InpSPS_Debug       = false; // Imprimir score SPS en journal

