    //--- Validar relacion logica ATR
    if(InpBE_ATR_Mult >= InpSL_ATR_Mult)
        Print("[ORB_v3.2] ADVERTENCIA: BE_ATR_Mult(", InpBE_ATR_Mult,
              ") >= SL_ATR_Mult(", InpSL_ATR_Mult, ") вҖ” BE desactivado logicamente");

    if(InpSL_ATR_Mult >= InpTP_ATR_Mult)
        Print("[ORB_v3.2] ADVERTENCIA: SL_ATR_Mult(", InpSL_ATR_Mult,
              ") >= TP_ATR_Mult(", InpTP_ATR_Mult, ") вҖ” RR negativo");

