//+------------------------------------------------------------------+
//| OnDeinit                                                          |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
    if(g_atrHandle != INVALID_HANDLE)
        IndicatorRelease(g_atrHandle);
    Print("[ORB_v3.2] EA detenido. Razon: ", reason);
}

//+------------------------------------------------------------------+
//| OnTick                                                            |
//+------------------------------------------------------------------+
void OnTick()
{
    ManageBreakeven();
    CheckCancelOpposingPending();

    datetime curBarTime = iTime(_Symbol, PERIOD_M5, 0);
    if(curBarTime == g_lastBarTime) return;
    g_lastBarTime = curBarTime;

    MqlDateTime dt;
    TimeToStruct(curBarTime, dt);
    datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                               dt.year, dt.mon, dt.day));
    if(today != g_currentDay)
    {
        g_currentDay   = today;
        g_ordersPlaced = false;
        CancelAllPending();
    }

    if(g_ordersPlaced) return;
    if(InpOnlyOnePerDay && today == g_tradeDay) return;
    if(dt.hour != InpSessionHour || dt.min != InpSessionMinute) return;

    PlaceORBOrders(today);
}

//+------------------------------------------------------------------+
//| PlaceORBOrders                                                    |
//+------------------------------------------------------------------+
void PlaceORBOrders(datetime today)
{
    int barsNeeded = InpRangeCandles + InpSPS_Lookback + 5;

    double hi[], lo[], op[], cl[];
    ArraySetAsSeries(hi, true); ArraySetAsSeries(lo, true);
    ArraySetAsSeries(op, true); ArraySetAsSeries(cl, true);

    if(CopyHigh (_Symbol, PERIOD_M5, 1, barsNeeded, hi) != barsNeeded ||
       CopyLow  (_Symbol, PERIOD_M5, 1, barsNeeded, lo) != barsNeeded ||
       CopyOpen (_Symbol, PERIOD_M5, 1, barsNeeded, op) != barsNeeded ||
       CopyClose(_Symbol, PERIOD_M5, 1, barsNeeded, cl) != barsNeeded)
    {
        Print("[ORB_v3.2] CopyBuffer error — barras insuficientes");
        return;
    }

    //--- ATR de la ultima barra cerrada
    double atrArr[];
    ArraySetAsSeries(atrArr, true);
    if(CopyBuffer(g_atrHandle, 0, 1, 1, atrArr) != 1)
    {
        Print("[ORB_v3.2] ATR buffer error");
        return;
    }
    double atr = atrArr[0];
    if(atr <= _Point)
    {
        PrintFormat("[ORB_v3.2] ATR=%.5f invalido, skip", atr);
        return;
    }

    //--- Rango ORB
    double rangeHigh = hi[0];
    double rangeLow  = lo[0];
    for(int i = 1; i < InpRangeCandles; i++)
    {
        if(hi[i] > rangeHigh) rangeHigh = hi[i];
        if(lo[i] < rangeLow)  rangeLow  = lo[i];
    }

    //--- SPS
    SPS_Signal sps = SPS_NEUTRAL;
    if(InpSPS_Enabled)
        sps = CalcSPS(op, cl, hi, lo, InpRangeCandles, InpSPS_Lookback);

    //--- Distancias ATR con caps
    double minTP  = InpMinTP_Points * _Point;
    double maxTP  = InpMaxTP_Points * _Point;
    double tpDist = MathMax(minTP, MathMin(maxTP, atr * InpTP_ATR_Mult));
    double slDist = MathMax(minTP * 0.20, atr * InpSL_ATR_Mult);

    //--- Lote
    double lots = CalcLots(slDist);
    if(lots <= 0.0)
    {
        PrintFormat("[ORB_v3.2] Lote invalido: SL=%.5f ATR=%.5f", slDist, atr);
        return;
    }

    //--- Spread y precios
    double ask    = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
    double bid    = SymbolInfoDouble(_Symbol, SYMBOL_BID);
    double spread = ask - bid;

    //--- Niveles
    double buyEntry  = NormalizeDouble(rangeHigh + spread, _Digits);
    double buySL     = NormalizeDouble(buyEntry  - slDist, _Digits);
    double buyTP     = NormalizeDouble(buyEntry  + tpDist, _Digits);

    double sellEntry = NormalizeDouble(rangeLow  - spread, _Digits);
    double sellSL    = NormalizeDouble(sellEntry + slDist, _Digits);
    double sellTP    = NormalizeDouble(sellEntry - tpDist, _Digits);

    datetime expiry  = today + 86399;
    bool placed      = false;
    double beTrig    = atr * InpBE_ATR_Mult;

    PrintFormat("[ORB_v3.2] %s | Rng[%.2f-%.2f] %.0fpts | ATR=%.2f | TP=%.0fpts SL=%.0fpts BE=%.0fpts | lot=%.2f | SPS=%s",
        TimeToString(TimeCurrent(), TIME_DATE|TIME_MINUTES),
        rangeLow, rangeHigh, (rangeHigh - rangeLow) / _Point,
        atr, tpDist / _Point, slDist / _Point, beTrig / _Point,
        lots, SPSName(sps));

    //--- BUY STOP
    if(sps != SPS_BEARISH)
    {
        if(buyEntry > ask)
        {
            if(g_trade.BuyStop(lots, buyEntry, _Symbol, buySL, buyTP,
                               ORDER_TIME_SPECIFIED, expiry, InpComment))
            {
                placed = true;
                PrintFormat("[ORB_v3.2] BUY STOP OK  | %.2f  SL=%.2f  TP=%.2f | SPS=%s",
                    buyEntry, buySL, buyTP, SPSName(sps));
            }
            else
                PrintFormat("[ORB_v3.2] BUY STOP ERR [%d]: %s",
                    g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
        }
        else
            PrintFormat("[ORB_v3.2] BUY skipped: %.2f <= ask %.2f (breakout previo)", buyEntry, ask);
    }

    //--- SELL STOP
    if(sps != SPS_BULLISH)
    {
        if(sellEntry < bid)
        {
            if(g_trade.SellStop(lots, sellEntry, _Symbol, sellSL, sellTP,
                                ORDER_TIME_SPECIFIED, expiry, InpComment))
            {
                placed = true;
                PrintFormat("[ORB_v3.2] SELL STOP OK | %.2f  SL=%.2f  TP=%.2f | SPS=%s",
                    sellEntry, sellSL, sellTP, SPSName(sps));
            }
            else
                PrintFormat("[ORB_v3.2] SELL STOP ERR [%d]: %s",
                    g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
        }
        else
            PrintFormat("[ORB_v3.2] SELL skipped: %.2f >= bid %.2f (breakout previo)", sellEntry, bid);
    }

    if(placed)  g_ordersPlaced = true;
    else        Print("[ORB_v3.2] Ninguna orden colocada");
}

//+------------------------------------------------------------------+
//| CalcSPS — Session Pressure Score (lookback corto, recency bias)  |
//|                                                                   |
//| Velas pre-rango: startIdx = InpRangeCandles                      |
//|   i=0 → vela mas cercana al rango (peso maximo)                  |
//|   i=lookback-1 → vela mas antigua (peso minimo)                  |
//|                                                                   |
//| Score normalizado [-1, +1]                                        |
//|  >= +threshold  → BULLISH  (bloquea SELL)                        |
//|  <= -threshold  → BEARISH  (bloquea BUY)                         |
//|  entre ±thresh  → NEUTRAL  (ambas ordenes)                       |
//+------------------------------------------------------------------+
SPS_Signal CalcSPS(const double &op[], const double &cl[],
                   const double &hi[], const double &lo[],
                   int startIdx, int lookback)
{
    double totalWeight   = 0.0;
    double weightedScore = 0.0;
    int    validCandles  = 0;

    for(int i = 0; i < lookback; i++)
    {
        int j = startIdx + i;

        double barRange = hi[j] - lo[j];
        if(barRange <= 0.0) continue;

        double bodyRatio = MathAbs(cl[j] - op[j]) / barRange;
        int    direction = (cl[j] >= op[j]) ? 1 : -1;
        double weight    = InpSPS_RecencyBias
                           ? (double)(lookback - i) / (double)lookback
                           : 1.0;

        weightedScore += (double)direction * bodyRatio * weight;
        totalWeight   += weight;
        validCandles++;
    }

    if(validCandles == 0 || totalWeight <= 0.0) return SPS_NEUTRAL;

    double score = weightedScore / totalWeight;

    if(InpSPS_Debug)
        PrintFormat("[SPS] score=%.4f  thresh=+-%.2f  lookback=%d  -> %s",
            score, InpSPS_Threshold, lookback,
            score >=  InpSPS_Threshold ? "BULLISH" :
            score <= -InpSPS_Threshold ? "BEARISH" : "NEUTRAL");

    if(score >=  InpSPS_Threshold) return SPS_BULLISH;
    if(score <= -InpSPS_Threshold) return SPS_BEARISH;
    return SPS_NEUTRAL;
}

//+------------------------------------------------------------------+
//| ManageBreakeven — BE basado en ATR (v3.1+)                       |
//|                                                                   |
//| Trigger: reconstruye ATR desde el SL colocado al abrir           |
//|   atr_implied  = slDist / InpSL_ATR_Mult                         |
//|   triggerDist  = atr_implied x InpBE_ATR_Mult                    |
//|                                                                   |
//| Actua en cada tick — solo modifica cuando hay cambio real         |
//+------------------------------------------------------------------+
void ManageBreakeven()
{
    if(!InpBE_Enabled) return;
    if(InpBE_ATR_Mult >= InpSL_ATR_Mult) return;  // guardia logica silenciosa

    for(int i = PositionsTotal() - 1; i >= 0; i--)
    {
        ulong ticket = PositionGetTicket(i);
        if(!PositionSelectByTicket(ticket))                                    continue;
        if((ulong)PositionGetInteger(POSITION_MAGIC) != InpMagicNumber)       continue;
        if(PositionGetString(POSITION_SYMBOL)        != _Symbol)              continue;

        ENUM_POSITION_TYPE posType = (ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE);
        double entry = PositionGetDouble(POSITION_PRICE_OPEN);
        double sl    = PositionGetDouble(POSITION_SL);
        double tp    = PositionGetDouble(POSITION_TP);
        if(tp <= 0 || sl <= 0) continue;

        double curPrice = (posType == POSITION_TYPE_BUY)
                          ? SymbolInfoDouble(_Symbol, SYMBOL_BID)
                          : SymbolInfoDouble(_Symbol, SYMBOL_ASK);

        double slDist      = MathAbs(entry - sl);
        double atrImplied  = (InpSL_ATR_Mult > 0) ? slDist / InpSL_ATR_Mult : slDist;
        double triggerDist = atrImplied * InpBE_ATR_Mult;
        double lockDist    = InpBE_LockPoints * _Point;
        double newSL;

        if(posType == POSITION_TYPE_BUY)
        {
            if(curPrice < entry + triggerDist) continue;
            newSL = NormalizeDouble(entry + lockDist, _Digits);
            if(sl >= newSL - _Point) continue;
        }
        else
        {
            if(curPrice > entry - triggerDist) continue;
            newSL = NormalizeDouble(entry - lockDist, _Digits);
            if(sl <= newSL + _Point) continue;
        }

        if(g_trade.PositionModify(ticket, newSL, tp))
            PrintFormat("[ORB_v3.2 BE] ticket=%llu | SL->%.2f | atr_impl=%.2f | trig=%.2f | cur=%.2f",
                ticket, newSL, atrImplied,
                entry + (posType == POSITION_TYPE_BUY ? 1.0 : -1.0) * triggerDist,
                curPrice);
        else
            PrintFormat("[ORB_v3.2 BE] ModifyError [%d]: %s",
                g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription());
    }
}

//+------------------------------------------------------------------+
//| CheckCancelOpposingPending                                        |
//+------------------------------------------------------------------+
void CheckCancelOpposingPending()
{
    for(int i = 0; i < PositionsTotal(); i++)
    {
        ulong ticket = PositionGetTicket(i);
        if(!PositionSelectByTicket(ticket))                              continue;
        if((ulong)PositionGetInteger(POSITION_MAGIC) != InpMagicNumber) continue;
        if(PositionGetString(POSITION_SYMBOL)        != _Symbol)        continue;

        datetime posTime = (datetime)PositionGetInteger(POSITION_TIME);
        MqlDateTime dtPos;
        TimeToStruct(posTime, dtPos);
        datetime posDay = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                                    dtPos.year, dtPos.mon, dtPos.day));
        if(posDay > g_tradeDay) g_tradeDay = posDay;

        CancelAllPending();
        return;
    }
}

//+------------------------------------------------------------------+
//| CancelAllPending                                                  |
//+------------------------------------------------------------------+
void CancelAllPending()
{
    for(int i = OrdersTotal() - 1; i >= 0; i--)
    {
        ulong ticket = OrderGetTicket(i);
        if(!OrderSelect(ticket))                                                 continue;
        if((ulong)OrderGetInteger(ORDER_MAGIC) != InpMagicNumber)               continue;
        if(OrderGetString(ORDER_SYMBOL)        != _Symbol)                      continue;

        if(!g_trade.OrderDelete(ticket))
            PrintFormat("[ORB_v3.2] DeleteError [%d]: %s ticket=%llu",
                g_trade.ResultRetcode(), g_trade.ResultRetcodeDescription(), ticket);
    }
}

//+------------------------------------------------------------------+
//| CalcLots                                                          |
//+------------------------------------------------------------------+
double CalcLots(double slDist)
{
    double riskAmt = InpUsePercentRisk
                   ? AccountInfoDouble(ACCOUNT_BALANCE) * InpRiskPercent / 100.0
                   : InpRiskUSD;
    if(riskAmt <= 0) return 0;

    double tickSz  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
    double tickVal = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
    if(tickSz <= 0 || tickVal <= 0 || slDist <= 0) return 0;

    double riskPerLot = (slDist / tickSz) * tickVal;
    if(riskPerLot <= 0) return 0;

    double raw     = riskAmt / riskPerLot;
    double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
    double lotMin  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
    double lotMax  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

    double lots = MathFloor(raw / lotStep) * lotStep;
    return NormalizeDouble(MathMax(lotMin, MathMin(lotMax, lots)), 2);
}

//+------------------------------------------------------------------+
//| OnTradeTransaction — cancelacion inmediata al fill               |
//+------------------------------------------------------------------+
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
{
    if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
    if(!HistoryDealSelect(trans.deal))           return;

    if((ulong)HistoryDealGetInteger(trans.deal, DEAL_MAGIC) != InpMagicNumber) return;
    if(HistoryDealGetString(trans.deal, DEAL_SYMBOL)        != _Symbol)        return;
    if((ENUM_DEAL_ENTRY)HistoryDealGetInteger(trans.deal, DEAL_ENTRY) != DEAL_ENTRY_IN) return;

    datetime dealTime = (datetime)HistoryDealGetInteger(trans.deal, DEAL_TIME);
    MqlDateTime dtD;
    TimeToStruct(dealTime, dtD);
    g_tradeDay = StringToTime(StringFormat("%04d.%02d.%02d 00:00:00",
                                           dtD.year, dtD.mon, dtD.day));
    CancelAllPending();
    PrintFormat("[ORB_v3.2 TX] Deal %llu fill -> pendientes cancelados", trans.deal);
}

//+------------------------------------------------------------------+
//| SPSName                                                           |
//+------------------------------------------------------------------+
string SPSName(SPS_Signal s)
{
    switch(s)
    {
        case SPS_BULLISH: return "BULLISH";
        case SPS_BEARISH: return "BEARISH";
        default:          return "NEUTRAL";
    }
}

